using sv_5001897b754047a5a2366d1f6d3d009e.Client.Services;

namespace sv_5001897b754047a5a2366d1f6d3d009e.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 20, 9, 30, 0, TimeSpan.FromHours(-4)) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 21, 6, 0, 0, TimeSpan.FromHours(-4)) },
                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = new DateTimeOffset(2026, 5, 23, 14, 15, 0, TimeSpan.FromHours(-5)) },
            ]
        },
        ["TRK-002"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.FromHours(-7)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.FromHours(-7)) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTimeOffset(2026, 5, 19, 16, 45, 0, TimeSpan.FromHours(-7)) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.FromHours(-7)) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 22, 11, 23, 0, TimeSpan.FromHours(-7)) },
            ]
        },
        ["TRK-003"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-003",
            Status = "Out for Delivery",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 24, 18, 0, 0, TimeSpan.FromHours(-5)),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Dallas, TX", Timestamp = new DateTimeOffset(2026, 5, 22, 11, 0, 0, TimeSpan.FromHours(-5)) },
                new StatusUpdate { Description = "Arrived at local facility", Location = "Austin, TX", Timestamp = new DateTimeOffset(2026, 5, 23, 20, 30, 0, TimeSpan.FromHours(-5)) },
                new StatusUpdate { Description = "Out for delivery", Location = "Austin, TX", Timestamp = new DateTimeOffset(2026, 5, 24, 7, 45, 0, TimeSpan.FromHours(-5)) },
            ]
        }
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

