using sv_5001897b754047a5a2366d1f6d3d009e.Client.Services;

namespace sv_5001897b754047a5a2366d1f6d3d009e.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        app.MapGet("api/shipments/{trackingNumber}", async (string trackingNumber, IShipmentService service, CancellationToken ct) =>
        {
            try
            {
                var shipment = await service.GetShipmentAsync(trackingNumber, ct);
                return Results.Ok(shipment);
            }
            catch (KeyNotFoundException)
            {
                return Results.NotFound();
            }
        });
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_5001897b754047a5a2366d1f6d3d009e.Client.Services
@rendermode InteractiveAuto
@implements IAsyncDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Tracking History</h3>
